const body = $input.item.json.body || $input.item.json;

if (body['hub.mode'] === 'subscribe' && body['hub.verify_token']) {
  return { json: { verification: true, challenge: body['hub.challenge'] } };
}

const entry = body.entry?.[0];
if (!entry) return { json: { error: 'No entry data' } };

const changes = entry.changes || [];
const messaging = entry.messaging || [];

let data = {
  platform: '',
  type: '',
  userId: '',
  userName: '',
  message: '',
  postId: '',
  commentId: '',
  timestamp: new Date().toISOString()
};

if (messaging.length > 0 && messaging[0].message) {
  data.type = 'dm';
  data.userId = messaging[0].sender.id;
  data.message = messaging[0].message.text || '';
  data.platform = messaging[0].sender.id.length > 15 ? 'instagram' : 'facebook';
} else if (changes.length > 0) {
  const change = changes[0];
  if (change.field === 'feed' && change.value.item === 'comment') {
    data.type = 'comment';
    data.platform = 'facebook';
    data.commentId = change.value.comment_id;
    data.postId = change.value.post_id;
    data.userId = change.value.from?.id || '';
    data.userName = change.value.from?.name || '';
    data.message = change.value.message || '';
  } else if (change.field === 'comments') {
    data.type = 'comment';
    data.platform = 'instagram';
    data.commentId = change.value.id;
    data.userId = change.value.from?.id || '';
    data.userName = change.value.from?.username || '';
    data.message = change.value.text || '';
  }
}

return { json: data };

const message = ($json.message || '').toLowerCase().trim();

if (!message || message.length < 2) {
  return { json: { shouldProcess: false, reason: 'empty' } };
}

const spam = ['viagra', 'casino', 'ganador', 'premio gratis', 'click aqui'];
if (spam.some(k => message.includes(k))) {
  return { json: { ...$json, shouldProcess: false, reason: 'spam' } };
}

const urgent = ['reclamo', 'queja', 'devolver', 'reembolso'];
const needsHuman = urgent.some(k => message.includes(k));

return { json: { ...$json, shouldProcess: true, needsHuman } };

// Extraer respuesta de Gemini
const geminiResponse = $input.item.json;
const aiText = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || 'Gracias por tu mensaje 😊';

const prev = $('Filtrar Spam').item.json;
return { json: { ...prev, aiResponse: aiText.trim(), aiModel: 'Gemini' } };
